import{_ as e,o as a,c as r,ah as i}from"./chunks/framework.DsjyFzT5.js";const l="/assets/schedule-all1.CG9oSNTN.jpg",s="/assets/schedule-all2.CMt9S28_.jpg",p="/assets/schedule.COCOt6j6.jpg",n="/assets/right-hand-34-1.BiQMxnBr.jpg",o="/assets/right-hand-34-2.DRaW1eZB.jpg",h="/assets/right-hand-34-3.DOgi1g6W.jpg",c="/assets/right-hand-34-4.05lG-yMU.jpg",d="/assets/right-hand-34-5.BJ0LtOq9.jpg",g="/assets/right-hand-34-6.B4bTX7J6.jpg",b="/assets/right-hand-34-7.W57j1fGv.jpg",m="/assets/pin-jun-lv12.B8zjZflb.png",_="/assets/sound_group.Cl4CFy4y.png",u="/assets/zi-ran-da-diao.D3L9YF3Z.png",f="/assets/standard-xian-sound.DoClbbGJ.png",x="/assets/pin-jun-lv12-jita.DOXc5cyk.png",y="/assets/big-c.8P68QDIm.png",k="/assets/yin-shu.IvtlZhUE.jpg",w="/assets/yin-shu2.BDdOyOxJ.jpg",q="/assets/yin-shu3.Dv3-B3Qi.jpg",D=JSON.parse('{"title":"跟着吉他大学霸学吉他","description":"","frontmatter":{"title":"跟着吉他大学霸学吉他","date":"2022-08-21T00:00:00.000Z","category":"music","cover":"/images/bg-guitar-schedule.jpg","tags":["music","guitar"]},"headers":[],"relativePath":"_post/music/guitar2.md","filePath":"_post/music/guitar2.md"}'),B={name:"_post/music/guitar2.md"};function v(P,t,j,C,E,z){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="跟着吉他大学霸学吉他" tabindex="-1">跟着吉他大学霸学吉他 <a class="header-anchor" href="#跟着吉他大学霸学吉他" aria-label="Permalink to &quot;跟着吉他大学霸学吉他&quot;">​</a></h1><h2 id="入门必看防弯路" tabindex="-1">入门必看防弯路 <a class="header-anchor" href="#入门必看防弯路" aria-label="Permalink to &quot;入门必看防弯路&quot;">​</a></h2><ul><li><a href="https://www.bilibili.com/video/BV1rS4y1W7is" target="_blank" rel="noreferrer">新手整体规划</a><ul><li>了解琴、<a href="https://www.bilibili.com/video/BV1RB4y1Y7Dj" target="_blank" rel="noreferrer">保养</a></li><li>识谱：六线谱、简谱、五线谱</li><li>乐理</li><li>击弦、滑弦、勾弦、扫弦，三个黑铁 =&gt; 扫弦 =&gt; 黄金*3 =&gt; 第二种扫弦 =&gt; 砖石 =&gt; 大横按 =&gt; 大师</li></ul></li><li><a href="https://www.bilibili.com/video/BV1rS4y1J7TS" target="_blank" rel="noreferrer">每天练琴内容</a>，</li><li><a href="https://www.bilibili.com/video/BV14d4y1R7dA" target="_blank" rel="noreferrer">新手常见问题</a></li><li><a href="https://space.bilibili.com/87918598/article" target="_blank" rel="noreferrer">分级练习曲</a> -- 专栏文集</li></ul><p>吉他分类：古典（古典音乐）、民谣（弹唱伴奏、指弹）、电（摇滚），木吉他常备当做民谣吉他和古典吉他的总称</p><p>时刻注意：</p><ol><li>曲子练习，需要唱简谱</li><li>姿势做标准，不能将就，可以慢，不能错</li><li>坚持</li></ol><p>整体规划表：</p><p><img src="'+l+'" alt=""></p><p><img src="'+s+'" alt=""></p><p>每日练习时刻表：</p><p><img src="'+p+'" alt=""></p><h2 id="右手基基本功" tabindex="-1">右手基基本功 <a class="header-anchor" href="#右手基基本功" aria-label="Permalink to &quot;右手基基本功&quot;">​</a></h2><p>分级别练习</p><p><img src="'+n+'" alt=""></p><p><img src="'+o+'" alt=""></p><p><img src="'+h+'" alt=""></p><p><img src="'+c+'" alt=""></p><p><img src="'+d+'" alt=""></p><p><img src="'+g+'" alt=""></p><p><img src="'+b+'" alt=""></p><h2 id="左手基本功" tabindex="-1"><a href="https://www.bilibili.com/video/BV15b4y177PN/?spm_id_from=333.788&amp;vd_source=554c813e9abf3a2eb6e0cf650060074e" target="_blank" rel="noreferrer">左手基本功</a> <a class="header-anchor" href="#左手基本功" aria-label="Permalink to &quot;[左手基本功](https://www.bilibili.com/video/BV15b4y177PN/?spm_id_from=333.788&amp;vd_source=554c813e9abf3a2eb6e0cf650060074e)&quot;">​</a></h2><ul><li><p>靠弦按弦练习</p></li><li><p>离弦按弦练习</p></li><li><p>正向爬格子</p></li><li><p>反向爬格子</p></li><li><p>单项爬格子</p></li></ul><p>左手出现问题<a href="https://www.bilibili.com/video/BV13Z4y1i7e1?spm_id_from=333.999.0.0&amp;vd_source=554c813e9abf3a2eb6e0cf650060074e" target="_blank" rel="noreferrer">参考</a></p><h2 id="基础乐理" tabindex="-1">基础乐理 <a class="header-anchor" href="#基础乐理" aria-label="Permalink to &quot;基础乐理&quot;">​</a></h2><ul><li>咋震动(一秒多少次) 音调</li><li>震多大 响度</li><li>啥在震 音色</li><li>震多久 长短</li></ul><p>绝对音高： 以震动频率来命的名字就是绝对音高</p><table tabindex="0"><thead><tr><th style="text-align:center;">频率(Hz)</th><th style="text-align:center;">音名</th><th style="text-align:center;">唱名</th></tr></thead><tbody><tr><td style="text-align:center;">493.88</td><td style="text-align:center;">B</td><td style="text-align:center;">si</td></tr><tr><td style="text-align:center;">440.00</td><td style="text-align:center;">A</td><td style="text-align:center;">la</td></tr><tr><td style="text-align:center;">392.00</td><td style="text-align:center;">G</td><td style="text-align:center;">sol</td></tr><tr><td style="text-align:center;">349.23</td><td style="text-align:center;">F</td><td style="text-align:center;">fa</td></tr><tr><td style="text-align:center;">329.63</td><td style="text-align:center;">E</td><td style="text-align:center;">mi</td></tr><tr><td style="text-align:center;">293.66</td><td style="text-align:center;">D</td><td style="text-align:center;">re</td></tr><tr><td style="text-align:center;">261.64</td><td style="text-align:center;">C</td><td style="text-align:center;">do</td></tr></tbody></table><p>规定频率每翻倍或减半依然叫这个音，为什么呢，因为人耳对音高的感觉主要取决于频率比，而不是频率差，(05:43)一般人认为 440hz 到 880Hz 的音差和 246.94hz 到 493.88Hz 的音差一样大</p><blockquote><p>音高: 在音乐领域里指的是人类心理对音符基频之感受。[1]<br> 基频：当发声体由于振动而发出声音时，声音一般可以分解为许多单纯的正弦波，也就是说所有的自然声音基本都是由许多频率不同的正弦波组成的，其中频率最低的正弦波即为基音，而其他频率较高的正弦波则为泛音。[2]<br> 音差？没找到详细的名词解释，可参考<a href="https://www.zhihu.com/question/307553920" target="_blank" rel="noreferrer">相关链接</a>理解下</p></blockquote><p>各个音的绝对准确高度和他们的相互关系，是确定调式和音高的基础</p><blockquote><p>调式: 若干个以特定顺序连接起来的音以一个主音为中心形成的集合[3]</p></blockquote><h3 id="_12-平均律" tabindex="-1">12 平均律 <a class="header-anchor" href="#_12-平均律" aria-label="Permalink to &quot;12 平均律&quot;">​</a></h3><p>一组有12个间隔均等的音组成的音律叫做12平均律</p><p><a href="https://www.bilibili.com/video/BV1QU4y1R7hg" target="_blank" rel="noreferrer">看视频吧，更易懂，06：34</a></p><p>每个相邻的音，分成12份，每个相邻的音都是大约1.05946倍，其中有7个是前面讲到的CDEFGAB，剩余5个可以叫升比他高的音或降比它低的音</p><p><img src="'+m+'" alt=""></p><p>人类听觉范围20Hz-20000Hz,能听到大概10组音，吉他能演奏的音如下</p><p><img src="'+_+'" alt=""></p><h3 id="固定调唱名法" tabindex="-1">固定调唱名法 <a class="header-anchor" href="#固定调唱名法" aria-label="Permalink to &quot;固定调唱名法&quot;">​</a></h3><p>固定调唱名法：用分组和字母来代替具体频率命名的方法</p><h3 id="大调式" tabindex="-1">大调式 <a class="header-anchor" href="#大调式" aria-label="Permalink to &quot;大调式&quot;">​</a></h3><p>自然大调式</p><p><img src="'+u+'" alt=""></p><p>命名方式 主音(自然)大调，eg:c大调</p><h3 id="首调唱名法" tabindex="-1">首调唱名法 <a class="header-anchor" href="#首调唱名法" aria-label="Permalink to &quot;首调唱名法&quot;">​</a></h3><p>首调唱名法：只称呼音级、序号、不代表具体音的叫法</p><h2 id="全指版音阶系统教学" tabindex="-1">全指版音阶系统教学 <a class="header-anchor" href="#全指版音阶系统教学" aria-label="Permalink to &quot;全指版音阶系统教学&quot;">​</a></h2><p>都是标准音时，空弦音6-1弦分别是E2、A2、D3、G3、B3、E4</p><p><img src="'+f+'" alt=""></p><p>品与品的音高关系：越靠近琴头音调约低，每个品格与挨着的品格相差半音</p><p>从六弦空弦音开始，顺次往右按住每品弹，到与空弦音重复的品就跳过这一品，去弹下一根弦的空弦音，这不就和12平均律的音列一模一样吗（试着弹一下 ，很神奇）</p><p>小公式：</p><p>除了2、3弦，低弦n品 = 高弦n品 + 5品</p><p>2弦n品 = 3弦n品 + 4品</p><p>从任意一品开始都可以弹出一个12平均律音列</p><p><img src="'+x+'" alt=""></p><p>把位：指板上某品到某品的区域</p><h3 id="音阶的弹法咋来的" tabindex="-1">音阶的弹法咋来的 <a class="header-anchor" href="#音阶的弹法咋来的" aria-label="Permalink to &quot;音阶的弹法咋来的&quot;">​</a></h3><p>C大调弹哪些地方</p><p><img src="'+y+'" alt=""></p><p>弹法见<a href="https://www.bilibili.com/video/BV1X44y1N7x5" target="_blank" rel="noreferrer">视频</a></p><h2 id="唱准音" tabindex="-1">唱准音 <a class="header-anchor" href="#唱准音" aria-label="Permalink to &quot;唱准音&quot;">​</a></h2><p>音域：人能发出的最低音到最高音的范围，一般男生C2-C5，女生C3-C6</p><p>安卓用户下载：专业调音器 苹果用户下载：tuner</p><p>三步法：</p><ol><li>弹这个音，确认音高</li><li>唱，什么字都行，保持一致</li><li>变，像目标音调高 || 调低</li></ol><p>跟练：</p><ul><li><a href="https://www.bilibili.com/video/BV1XV4y1u7AD" target="_blank" rel="noreferrer">视频链接</a>，08:00</li><li><a href="https://www.bilibili.com/read/cv18530283" target="_blank" rel="noreferrer">配套资料</a></li></ul><h2 id="吉他调式和弦级数原理" tabindex="-1">吉他调式和弦级数原理 <a class="header-anchor" href="#吉他调式和弦级数原理" aria-label="Permalink to &quot;吉他调式和弦级数原理&quot;">​</a></h2><p>和弦：按三度关系排列起来的三个以上的音的结合</p><p>音程：某个音比某个音高低多少叫音程</p><p>A比B高n度的音：B = A + n%7 - 1 + Math.floor(n/7)组</p><p>高1度？？</p><p>音数：音程中包含的全音和半音的数量，两个挨着的音相差半音，记作0.5</p><p><img src="'+k+'" alt=""></p><p>大三度：音数=2 小三度：音数=1.5</p><h3 id="三和弦" tabindex="-1">三和弦 <a class="header-anchor" href="#三和弦" aria-label="Permalink to &quot;三和弦&quot;">​</a></h3><p>按三度关系组合起来的音，其中最低的音叫根音、中间的音叫三音、最高的音叫五音</p><p>根音是啥，叫啥和弦，其中：</p><ul><li>根音与三音是大三度音时叫大三和弦</li><li>根音与三音是小三度音时叫小三和弦 注意：五音和根音的关系都是纯五度</li></ul><p>有符合级数规律但非纯五度的组合吗？？</p><p><img src="'+w+'" alt=""><img src="'+q+'" alt=""></p><h3 id="跟练" tabindex="-1">跟练 <a class="header-anchor" href="#跟练" aria-label="Permalink to &quot;跟练&quot;">​</a></h3><p><a href="https://www.bilibili.com/video/BV1ju411i7yA" target="_blank" rel="noreferrer">跟练视频 </a></p><p>E2开始的0-3品音阶</p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><p>[1] <a href="https://zh.m.wikipedia.org/zh-cn/%E9%9F%B3%E9%AB%98" target="_blank" rel="noreferrer">维基百科-音高</a><br> [2] <a href="https://zh.m.wikipedia.org/zh-cn/%E5%9F%BA%E6%9C%AC%E9%A0%BB%E7%8E%87" target="_blank" rel="noreferrer">维基百科-基频</a><br> [3] <a href="https://zh.wikipedia.org/wiki/%E8%B0%83%E5%BC%8F" target="_blank" rel="noreferrer">维基百科-调式</a></p>',87)])])}const V=e(B,[["render",v]]);export{D as __pageData,V as default};
